    58→	RespondList(w, r, http.StatusOK, releases, page, perPage, total)
    59→}
    60→
    61→// ListByProject handles GET /projects/{projectId}/releases — returns releases for all sources in a project.
    62→func (h *ReleasesHandler) ListByProject(w http.ResponseWriter, r *http.Request) {
