   749→// EnqueueAgentRun creates an agent_run row and enqueues a River AgentJobArgs.
   750→// This follows the transactional outbox pattern for zero-loss guarantee.
   751→func (s *PgStore) EnqueueAgentRun(ctx context.Context, projectID, trigger, version string) error {
   752→	tx, err := s.pool.Begin(ctx)
   753→	if err != nil {
   754→		return fmt.Errorf("begin tx: %w", err)
   755→	}
   756→	defer tx.Rollback(ctx)
   757→
   758→	var runID string
   759→	err = tx.QueryRow(ctx,
   760→		`INSERT INTO agent_runs (project_id, trigger, version, status)
   761→		 VALUES ($1, $2, $3, 'pending')
   762→		 RETURNING id`, projectID, trigger, version,
   763→	).Scan(&runID)
   764→	if err != nil {
   765→		return fmt.Errorf("insert agent run: %w", err)
   766→	}
   767→
   768→	if s.river != nil {
   769→		_, err = s.river.InsertTx(ctx, tx, queue.AgentJobArgs{
   770→			AgentRunID: runID,
   771→			ProjectID:  projectID,
   772→			Version:    version,
   773→		}, nil)
   774→		if err != nil {
   775→			return fmt.Errorf("enqueue agent job: %w", err)
   776→		}
   777→	}
   778→
   779→	return tx.Commit(ctx)
   780→}
