   784→// UpdateAgentRunStatus sets the status of an agent run and updates the
   785→// started_at timestamp when transitioning to "running".
   786→func (s *PgStore) UpdateAgentRunStatus(ctx context.Context, id, status string) error {
   787→	var query string
   788→	switch status {
   789→	case "running":
   790→		query = `UPDATE agent_runs SET status = $1, started_at = NOW() WHERE id = $2`
   791→	case "completed":
   792→		query = `UPDATE agent_runs SET status = $1, completed_at = NOW() WHERE id = $2`
   793→	default:
   794→		query = `UPDATE agent_runs SET status = $1 WHERE id = $2`
   795→	}
   796→	tag, err := s.pool.Exec(ctx, query, status, id)
   797→	if err != nil {
   798→		return fmt.Errorf("update agent run status: %w", err)
   799→	}
   800→	if tag.RowsAffected() == 0 {
   801→		return fmt.Errorf("agent run not found: %s", id)
   802→	}
   803→	return nil
   804→}
