   806→// CreateSemanticRelease inserts a semantic release and its source release links
   807→// in a single transaction. The sr.ID field is populated on success.
   808→func (s *PgStore) CreateSemanticRelease(ctx context.Context, sr *models.SemanticRelease, releaseIDs []string) error {
   809→	tx, err := s.pool.Begin(ctx)
   810→	if err != nil {
   811→		return fmt.Errorf("begin tx: %w", err)
   812→	}
   813→	defer tx.Rollback(ctx)
   814→
   815→	err = tx.QueryRow(ctx,
   816→		`INSERT INTO semantic_releases (project_id, version, report, status, completed_at)
   817→		 VALUES ($1, $2, $3, $4, $5)
   818→		 RETURNING id, created_at`,
   819→		sr.ProjectID, sr.Version, sr.Report, sr.Status, sr.CompletedAt,
   820→	).Scan(&sr.ID, &sr.CreatedAt)
   821→	if err != nil {
   822→		return fmt.Errorf("insert semantic release: %w", err)
   823→	}
   824→
   825→	for _, relID := range releaseIDs {
   826→		_, err = tx.Exec(ctx,
   827→			`INSERT INTO semantic_release_sources (semantic_release_id, release_id)
   828→			 VALUES ($1, $2) ON CONFLICT DO NOTHING`,
   829→			sr.ID, relID,
   830→		)
   831→		if err != nil {
   832→			return fmt.Errorf("insert semantic release source: %w", err)
   833→		}
   834→	}
   835→
   836→	return tx.Commit(ctx)
   837→}
