   929→func (s *PgStore) GetTrend(ctx context.Context, granularity string, start, end time.Time) ([]TrendBucket, error) {
   930→	// Validate granularity to one of three literal values (no injection risk).
   931→	var trunc string
   932→	switch granularity {
   933→	case "daily":
   934→		trunc = "day"
   935→	case "weekly":
   936→		trunc = "week"
   937→	case "monthly":
   938→		trunc = "month"
   939→	default:
   940→		return nil, fmt.Errorf("invalid granularity: %s", granularity)
   941→	}
   942→
   943→	query := fmt.Sprintf(`
   944→		WITH buckets AS (
   945→			SELECT date_trunc('%s', gs)::date AS period
   946→			FROM generate_series($1::timestamptz, $2::timestamptz, '1 %s'::interval) gs
   947→		)
   948→		SELECT
   949→			b.period,
   950→			COALESCE(r.cnt, 0) AS releases,
   951→			COALESCE(sr.cnt, 0) AS semantic_releases
   952→		FROM buckets b
   953→		LEFT JOIN (
   954→			SELECT date_trunc('%s', COALESCE(released_at, created_at))::date AS period,
   955→			       COUNT(*) AS cnt
   956→			FROM releases
   957→			WHERE COALESCE(released_at, created_at) >= $1 AND COALESCE(released_at, created_at) < $2
   958→			GROUP BY 1
   959→		) r ON r.period = b.period
   960→		LEFT JOIN (
   961→			SELECT date_trunc('%s', created_at)::date AS period,
   962→			       COUNT(*) AS cnt
   963→			FROM semantic_releases
   964→			WHERE created_at >= $1 AND created_at < $2
   965→			GROUP BY 1
   966→		) sr ON sr.period = b.period
   967→		ORDER BY b.period
   968→	`, trunc, trunc, trunc, trunc)
   969→
   970→	rows, err := s.pool.Query(ctx, query, start, end)
   971→	if err != nil {
   972→		return nil, fmt.Errorf("get trend: %w", err)
   973→	}
   974→	defer rows.Close()
   975→
   976→	var buckets []TrendBucket
   977→	for rows.Next() {
   978→		var b TrendBucket
   979→		var period time.Time
   980→		if err := rows.Scan(&period, &b.Releases, &b.SemanticReleases); err != nil {
   981→			return nil, fmt.Errorf("scan trend bucket: %w", err)
   982→		}
   983→		b.Period = period.Format("2006-01-02")
   984→		buckets = append(buckets, b)
   985→	}
   986→	if buckets == nil {
   987→		buckets = []TrendBucket{}
   988→	}
   989→	return buckets, nil
   990→}
